SELECT * FROM (SELECT TRY_CAST("YEAR" AS INTEGER) AS year, TRY_CAST("MONTH_NUM" AS INTEGER) AS month, TRY_CAST(left(CAST("FLT_DATE" AS VARCHAR), 10) AS DATE) AS date, NULLIF("APT_ICAO", '') AS apt_icao, NULLIF("APT_NAME", '') AS apt_name, NULLIF("STATE_NAME", '') AS state_name, NULLIF("ATFM_VERSION", '') AS atfm_version, TRY_CAST("FLT_ARR_1" AS DOUBLE) AS flt_arr_1, TRY_CAST("DLY_APT_ARR_1" AS DOUBLE) AS dly_apt_arr_1, TRY_CAST("DLY_APT_ARR_A_1" AS DOUBLE) AS dly_apt_arr_a_1, TRY_CAST("DLY_APT_ARR_C_1" AS DOUBLE) AS dly_apt_arr_c_1, TRY_CAST("DLY_APT_ARR_D_1" AS DOUBLE) AS dly_apt_arr_d_1, TRY_CAST("DLY_APT_ARR_E_1" AS DOUBLE) AS dly_apt_arr_e_1, TRY_CAST("DLY_APT_ARR_G_1" AS DOUBLE) AS dly_apt_arr_g_1, TRY_CAST("DLY_APT_ARR_I_1" AS DOUBLE) AS dly_apt_arr_i_1, TRY_CAST("DLY_APT_ARR_M_1" AS DOUBLE) AS dly_apt_arr_m_1, TRY_CAST("DLY_APT_ARR_N_1" AS DOUBLE) AS dly_apt_arr_n_1, TRY_CAST("DLY_APT_ARR_O_1" AS DOUBLE) AS dly_apt_arr_o_1, TRY_CAST("DLY_APT_ARR_P_1" AS DOUBLE) AS dly_apt_arr_p_1, TRY_CAST("DLY_APT_ARR_R_1" AS DOUBLE) AS dly_apt_arr_r_1, TRY_CAST("DLY_APT_ARR_S_1" AS DOUBLE) AS dly_apt_arr_s_1, TRY_CAST("DLY_APT_ARR_T_1" AS DOUBLE) AS dly_apt_arr_t_1, TRY_CAST("DLY_APT_ARR_V_1" AS DOUBLE) AS dly_apt_arr_v_1, TRY_CAST("DLY_APT_ARR_W_1" AS DOUBLE) AS dly_apt_arr_w_1, TRY_CAST("DLY_APT_ARR_NA_1" AS DOUBLE) AS dly_apt_arr_na_1, TRY_CAST("FLT_ARR_1_DLY" AS DOUBLE) AS flt_arr_1_dly, TRY_CAST("FLT_ARR_1_DLY_15" AS DOUBLE) AS flt_arr_1_dly_15 FROM "eurocontrol-apt-dly") WHERE date IS NOT NULL
